module multi_pipe_4bit #(
    parameter size = 4
) (
    input clk,
    input rst_n,
    input [size-1:0] mul_a,
    input [size-1:0] mul_b,
    output reg [2*size-1:0] mul_out
);

    wire [size-1:0] extend_a;
    wire [size-1:0] extend_b;
    assign extend_a = mul_a;
    assign extend_b = mul_b;

    wire [2*size-1:0] partial_products [size-1:0];
    genvar i;
    generate
        for (i = 0; i < size; i = i + 1) begin
            assign partial_products[i] = (extend_b[i]) ? (extend_a << i) : 'd0;
        end
    endgenerate

    reg [2*size-1:0] pp_reg [size-1:0];
    integer j;
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            for (j = 0; j < size; j = j + 1) begin
                pp_reg[j] <= 'd0;
            end
        end else begin
            pp_reg[0] <= partial_products[0];
            for (j = 1; j < size; j = j + 1) begin
                pp_reg[j] <= pp_reg[j-1] + partial_products[j];
            end
        end
    end

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            mul_out <= 'd0;
        end else begin
            mul_out <= pp_reg[size-1];
        end
    end

endmodule
